Code example:

try
{
    Prime.Base.ServiceStore<IDffService>.Service.SetDff(olbName, dataBin, this.tpTypeDieId, this.SessionContext);
}
catch (Prime.Base.Exceptions.DffException ex)
{
    ex.GetConsolePrintout(this.InstanceName, out var errorMessage, out var stackTrace);
    Prime.Base.ServiceStore<IConsoleService>.Service.PrintError(errorMessage, stackTrace, sessionContext);
}

